// 2) MOTOR DE SIMULACIÓN GPS/ETA
// Cada segundo mueve los buses, recalcula ocupación, retrasos y estado operativo.

function haversineKm(a, b) {
    const R = 6371;
    const dLat = (b.lat - a.lat) * Math.PI / 180;
    const dLng = (b.lng - a.lng) * Math.PI / 180;
    const lat1 = a.lat * Math.PI / 180;
    const lat2 = b.lat * Math.PI / 180;
    const s = Math.sin(dLat / 2) ** 2 + Math.cos(lat1) * Math.cos(lat2) * Math.sin(dLng / 2) ** 2;
    return 2 * R * Math.asin(Math.sqrt(s));
}

function pointAtProgress(route, progress) {
    const stops = route.stops;
    const total = route.distanceKm || 1;
    const target = progress * total;
    let acc = 0;
    for (let i = 0; i < stops.length - 1; i++) {
        const a = stops[i];
        const b = stops[i + 1];
        const d = haversineKm(a, b);
        if (acc + d >= target) {
            const ratio = d === 0 ? 0 : (target - acc) / d;
            return {
                lat: a.lat + (b.lat - a.lat) * ratio,
                lng: a.lng + (b.lng - a.lng) * ratio,
                segmentIndex: i,
                nextStop: b,
                prevStop: a
            };
        }
        acc += d;
    }
    return {
        lat: stops[stops.length - 1].lat,
        lng: stops[stops.length - 1].lng,
        segmentIndex: stops.length - 2,
        nextStop: stops[stops.length - 1],
        prevStop: stops[stops.length - 2]
    };
}

const routes = flow.get('bus.routes') || [];
let fleet = flow.get('bus.fleet') || [];
const running = flow.get('bus.running') !== false;
const speedFactor = Number(flow.get('bus.speedFactor') || 1);
const now = Date.now();
const last = Number(flow.get('bus.lastTick') || now);
const dt = Math.max(0.2, Math.min(3, (now - last) / 1000));
flow.set('bus.lastTick', now);

if (running && routes.length && fleet.length) {
    fleet = fleet.map(bus => {
        const route = routes.find(r => r.id === bus.routeId);
        if (!route || !bus.active) return bus;

        // Factor de tráfico dinámico: el tráfico cambia levemente para hacerlo más real.
        const wave = 1 + Math.sin(now / 30000 + route.order) * 0.06;
        const traffic = Math.max(0.72, Math.min(1.35, route.trafficBase * wave));
        const durationSec = Math.max(60, route.durationMin * 60 * traffic);
        const vehicleVariation = 0.92 + Math.random() * 0.18;
        bus.progress = (bus.progress + (dt * speedFactor * vehicleVariation / durationSec)) % 1;

        // Ocupación variable, pero controlada.
        if (Math.random() > 0.68) {
            bus.occupancy = Math.max(4, Math.min(100, bus.occupancy + Math.round((Math.random() - 0.48) * 9)));
        }

        // Retraso estimado en función de tráfico/ocupación.
        const calculatedDelay = Math.max(0, Math.round((traffic - 1) * 11 + (bus.occupancy > 85 ? 3 : 0) + Math.random() * 2));
        bus.delayMin = Math.round((bus.delayMin * 0.65) + (calculatedDelay * 0.35));
        const p = pointAtProgress(route, bus.progress);
        bus.lat = Number(p.lat.toFixed(6));
        bus.lng = Number(p.lng.toFixed(6));
        bus.nextStop = `${p.nextStop.code} — ${p.nextStop.name}`;
        bus.prevStop = `${p.prevStop.code} — ${p.prevStop.name}`;
        bus.segmentIndex = p.segmentIndex;
        bus.traffic = Number(traffic.toFixed(2));
        bus.speedKmh = Math.max(8, Math.round(route.avgSpeedKmh / traffic + (Math.random() - 0.5) * 4));
        bus.lastEvent = 'GPS actualizado';
        return bus;
    });
}

flow.set('bus.fleet', fleet);
msg.topic = 'system/tick';
msg.payload = { tick: now, running, buses: fleet.length };
return msg;

// 3) COMANDOS DESDE EL DASHBOARD
// El ui-template envía mensajes con topic cmd/* y este nodo cambia el estado del sistema.

const topic = msg.topic || '';
const payload = msg.payload || {};
let routes = flow.get('bus.routes') || [];
let fleet = flow.get('bus.fleet') || [];

if (topic === 'cmd/selectRoute') {
    const routeId = payload.routeId;
    if (routes.some(r => r.id === routeId)) {
        flow.set('bus.selectedRouteId', routeId);
    }
}

if (topic === 'cmd/toggle') {
    const current = flow.get('bus.running') !== false;
    flow.set('bus.running', !current);
}

if (topic === 'cmd/setRunning') {
    flow.set('bus.running', Boolean(payload.running));
}

if (topic === 'cmd/speed') {
    const value = Number(payload.speedFactor || 1);
    flow.set('bus.speedFactor', Math.max(0.25, Math.min(4, value)));
}

if (topic === 'cmd/resetFleet') {
    fleet = fleet.map((bus, index) => {
        const route = routes.find(r => r.id === bus.routeId);
        const routeBuses = fleet.filter(b => b.routeId === bus.routeId);
        const order = routeBuses.findIndex(b => b.id === bus.id);
        return {
            ...bus,
            progress: ((order >= 0 ? order : index) / Math.max(1, route?.busCount || 1) + Math.random() * 0.05) % 1,
            occupancy: Math.floor(18 + Math.random() * 52),
            delayMin: Math.floor(Math.random() * 3),
            active: true,
            lastEvent: 'Flota reiniciada desde dashboard'
        };
    });
    flow.set('bus.fleet', fleet);
}

if (topic === 'cmd/toggleBus') {
    const busId = payload.busId;
    fleet = fleet.map(bus => bus.id === busId ? { ...bus, active: !bus.active, lastEvent: 'Estado cambiado manualmente' } : bus);
    flow.set('bus.fleet', fleet);
}

msg.topic = 'system/command-applied';
msg.payload = { ok: true, command: topic, selectedRouteId: flow.get('bus.selectedRouteId') };
return msg;

// 4) CONSTRUCTOR DE SNAPSHOT PARA EL DASHBOARD
// Junta rutas, flota, KPIs, tabla y alertas en un solo msg.payload.

function clamp(n, min, max) { return Math.max(min, Math.min(max, n)); }
function pct(n) { return Math.round(n); }
function etaStatus(eta, occ, delay) {
    if (occ >= 92) return { label: 'Lleno', cls: 'bad' };
    if (delay >= 7 || eta >= 30) return { label: 'Demorado', cls: 'bad' };
    if (delay >= 3 || eta >= 16 || occ >= 80) return { label: 'Moderado', cls: 'warn' };
    return { label: 'A tiempo', cls: 'ok' };
}
function minutesToDestination(route, bus) {
    const remain = Math.max(0, 1 - Number(bus.progress || 0));
    return Math.max(0, Math.round(remain * route.durationMin * Number(bus.traffic || route.trafficBase || 1) + (bus.delayMin || 0)));
}
function minutesToOrigin(route, bus) {
    const remainCycle = Number(bus.progress || 0) < 0.02 ? 0 : (1 - Number(bus.progress || 0));
    return Math.max(0, Math.round(remainCycle * route.durationMin * Number(bus.traffic || route.trafficBase || 1)));
}

const routes = flow.get('bus.routes') || [];
const fleet = flow.get('bus.fleet') || [];
const selectedRouteId = flow.get('bus.selectedRouteId') || (routes[0] && routes[0].id);
const selectedRoute = routes.find(r => r.id === selectedRouteId) || routes[0] || null;
const running = flow.get('bus.running') !== false;
const speedFactor = Number(flow.get('bus.speedFactor') || 1);
const metadata = flow.get('bus.metadata') || {};
const now = new Date();

const enriched = fleet.map(bus => {
    const route = routes.find(r => r.id === bus.routeId) || {};
    const etaOrigin = minutesToOrigin(route, bus);
    const etaDest = minutesToDestination(route, bus);
    const state = etaStatus(etaDest, bus.occupancy || 0, bus.delayMin || 0);
    return {
        ...bus,
        routeName: route.name,
        routeLine: route.line,
        routeColor: route.color,
        origin: route.origin,
        destination: route.destination,
        etaOrigin,
        etaDest,
        status: state.label,
        statusClass: state.cls,
        progressPct: pct((bus.progress || 0) * 100)
    };
});

const selectedBuses = enriched.filter(b => selectedRoute && b.routeId === selectedRoute.id && b.active);
const allActive = enriched.filter(b => b.active);
const avgOccupancy = allActive.length ? pct(allActive.reduce((s, b) => s + (b.occupancy || 0), 0) / allActive.length) : 0;
const routeAvgOcc = selectedBuses.length ? pct(selectedBuses.reduce((s, b) => s + (b.occupancy || 0), 0) / selectedBuses.length) : 0;
const delayed = allActive.filter(b => b.statusClass === 'bad').length;
const nextBus = selectedBuses.slice().sort((a, b) => a.etaOrigin - b.etaOrigin)[0] || null;

let alerts = [];
enriched.forEach(b => {
    if (!b.active) alerts.push({ level: 'warn', text: `${b.id} está fuera de servicio`, routeId: b.routeId });
    if (b.occupancy >= 92) alerts.push({ level: 'bad', text: `${b.id} con ocupación crítica (${b.occupancy}%)`, routeId: b.routeId });
    if (b.delayMin >= 7) alerts.push({ level: 'bad', text: `${b.id} presenta retraso de ${b.delayMin} min`, routeId: b.routeId });
});
if (selectedRoute && selectedRoute.trafficBase >= 1.1) {
    alerts.push({ level: 'warn', text: `Tráfico alto en ${selectedRoute.id} ${selectedRoute.line}`, routeId: selectedRoute.id });
}
alerts = alerts.slice(0, 12);
flow.set('bus.alerts', alerts);

const routeSummary = routes.map(route => {
    const buses = enriched.filter(b => b.routeId === route.id && b.active);
    const avgOcc = buses.length ? pct(buses.reduce((s, b) => s + b.occupancy, 0) / buses.length) : 0;
    const minEta = buses.length ? Math.min(...buses.map(b => b.etaOrigin)) : null;
    const bad = buses.filter(b => b.statusClass === 'bad').length;
    return {
        id: route.id,
        line: route.line,
        name: route.name,
        origin: route.origin,
        destination: route.destination,
        color: route.color,
        buses: buses.length,
        avgOcc,
        minEta,
        bad,
        distanceKm: route.distanceKm,
        durationMin: route.durationMin,
        headwayMin: route.headwayMin
    };
});

const table = enriched
    .filter(b => selectedRoute ? b.routeId === selectedRoute.id : true)
    .sort((a, b) => a.etaOrigin - b.etaOrigin)
    .map(b => ({
        bus: b.id,
        plate: b.plate,
        driver: b.driver,
        routeId: b.routeId,
        route: `${b.routeId} · ${b.routeLine}`,
        origin: b.origin,
        destination: b.destination,
        nextStop: b.nextStop || b.destination,
        etaOrigin: b.etaOrigin,
        etaDest: b.etaDest,
        occupancy: b.occupancy,
        speedKmh: b.speedKmh || 0,
        delayMin: b.delayMin || 0,
        progressPct: b.progressPct,
        active: b.active,
        status: b.active ? b.status : 'Fuera de servicio',
        statusClass: b.active ? b.statusClass : 'off',
        lat: b.lat,
        lng: b.lng
    }));

msg.topic = 'dashboard/snapshot';
msg.payload = {
    type: 'snapshot',
    metadata,
    selectedRouteId,
    selectedRoute,
    routes,
    buses: enriched,
    selectedBuses,
    table,
    routeSummary,
    alerts,
    running,
    speedFactor,
    kpi: {
        activeTotal: allActive.length,
        activeSelected: selectedBuses.length,
        nextEta: nextBus ? nextBus.etaOrigin : null,
        nextBus: nextBus ? nextBus.id : '—',
        nextStop: nextBus ? nextBus.nextStop : '—',
        avgOccupancy,
        routeAvgOcc,
        delayed,
        alerts: alerts.length,
        selectedDistanceKm: selectedRoute ? selectedRoute.distanceKm : 0,
        selectedDurationMin: selectedRoute ? selectedRoute.durationMin : 0,
        reliability: clamp(100 - delayed * 4 - Math.round(avgOccupancy / 20), 62, 99),
        lastUpdate: now.toLocaleTimeString('es-EC', { hour12: false })
    }
};
return msg;

msg.payload = {
    ok: true,
    count: (flow.get('bus.routes') || []).length,
    routes: flow.get('bus.routes') || [],
    note: 'Catálogo de rutas del dashboard. Los horarios son simulados.'
};
return msg;

const routes = flow.get('bus.routes') || [];
const fleet = flow.get('bus.fleet') || [];
msg.payload = {
    ok: true,
    timestamp: new Date().toISOString(),
    running: flow.get('bus.running') !== false,
    selectedRouteId: flow.get('bus.selectedRouteId'),
    routes: routes.length,
    buses: fleet.length,
    telemetry: fleet
};
return msg;
